import java.util.Scanner;

public class SecureBufferExample {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.print("Enter a string: ");

        String userInput = scanner.nextLine(); // Read the entire line

        // Limit the length of user input to prevent buffer overflow
        if(userInput.length() > 10) {
            userInput = userInput.substring(0, 10); // Truncate input to fit buffer size
        }

        char[] buffer = new char[10];

        // Copy user input into buffer with proper bounds checking
        userInput.getChars(0, userInput.length(), buffer, 0);

        System.out.println("Buffer content: " + new String(buffer));
    }
}

